const http = require('http');
const https = require('https');
const url = require('url');
const path = require('path');
const fs = require('fs');
const vm = require('vm');

// ============================================
// Plugin Manager
// ============================================
class PluginManager {
  constructor() {
    this.plugins = new Map();
    this.hooks = {
      onRequest: [],
      onResponse: [],
      onError: [],
      onStartup: [],
      onShutdown: [],
    };
    this.pluginOrder = [];
  }

  /**
   * Register a plugin with the gateway.
   * Plugins must export an object with:
   *   - name: string
   *   - version: string (optional)
   *   - hooks: { onRequest?, onResponse?, onError?, onStartup?, onShutdown? }
   */
  registerPlugin(plugin) {
    if (!plugin || !plugin.name) {
      throw new Error('Plugin must have a "name" property');
    }

    if (this.plugins.has(plugin.name)) {
      console.warn(`[PluginManager] Plugin "${plugin.name}" is already registered. Overwriting.`);
      this.unregisterPlugin(plugin.name);
    }

    this.plugins.set(plugin.name, plugin);
    this.pluginOrder.push(plugin.name);

    // Register hooks
    for (const hookName of Object.keys(this.hooks)) {
      if (typeof plugin.hooks?.[hookName] === 'function') {
        this.hooks[hookName].push({
          pluginName: plugin.name,
          handler: plugin.hooks[hookName],
          priority: plugin.priority || 0,
        });
        // Sort by priority (higher priority runs first)
        this.hooks[hookName].sort((a, b) => b.priority - a.priority);
      }
    }

    console.log(`[PluginManager] Registered plugin: "${plugin.name}" v${plugin.version || '1.0.0'}`);
  }

  unregisterPlugin(name) {
    if (!this.plugins.has(name)) return;

    for (const hookName of Object.keys(this.hooks)) {
      this.hooks[hookName] = this.hooks[hookName].filter(h => h.pluginName !== name);
    }

    this.plugins.delete(name);
    this.pluginOrder = this.pluginOrder.filter(n => n !== name);
    console.log(`[PluginManager] Unregistered plugin: "${name}"`);
  }

  async executeHook(hookName, context) {
    const hookHandlers = this.hooks[hookName] || [];
    for (const hook of hookHandlers) {
      try {
        const result = await hook.handler(context);
        // If a hook returns { stop: true }, halt the chain
        if (result && result.stop) {
          context._stopped = true;
          break;
        }
      } catch (err) {
        console.error(`[PluginManager] Error in plugin "${hook.pluginName}" hook "${hookName}":`, err.message);
        if (hookName !== 'onError') {
          await this.executeHook('onError', { ...context, error: err, sourcePlugin: hook.pluginName });
        }
      }
    }
    return context;
  }

  getPlugin(name) {
    return this.plugins.get(name);
  }

  listPlugins() {
    return Array.from(this.plugins.values()).map(p => ({
      name: p.name,
      version: p.version || '1.0.0',
      description: p.description || '',
      priority: p.priority || 0,
    }));
  }
}

// ============================================
// Plugin Loader (supports multiple sources)
// ============================================
class PluginLoader {
  constructor(pluginManager, config) {
    this.pluginManager = pluginManager;
    this.config = config;
    this.sandboxedModules = new Map();
  }

  /**
   * Load a plugin from a file path using require()
   */
  loadFromFile(filePath) {
    const resolvedPath = path.resolve(filePath);

    if (!fs.existsSync(resolvedPath)) {
      throw new Error(`Plugin file not found: ${resolvedPath}`);
    }

    // Validate file extension
    const ext = path.extname(resolvedPath);
    if (!['.js', '.json'].includes(ext)) {
      throw new Error(`Unsupported plugin file extension: ${ext}`);
    }

    console.log(`[PluginLoader] Loading plugin from file: ${resolvedPath}`);

    // Clear require cache to allow hot-reloading
    delete require.cache[require.resolve(resolvedPath)];

    const plugin = require(resolvedPath);
    this.pluginManager.registerPlugin(plugin);
    return plugin;
  }

  /**
   * Load a plugin from a string of JavaScript code using vm.runInNewContext (sandboxed eval)
   */
  loadFromCode(code, pluginName = 'anonymous') {
    console.log(`[PluginLoader] Loading plugin from code: "${pluginName}"`);

    const sandbox = this._createSandbox(pluginName);

    try {
      const script = new vm.Script(code, {
        filename: `plugin_${pluginName}.js`,
        timeout: 5000,
      });

      script.runInNewContext(sandbox, { timeout: 5000 });

      if (!sandbox.module.exports || !sandbox.module.exports.name) {
        throw new Error('Plugin code must set module.exports with a "name" property');
      }

      const plugin = sandbox.module.exports;
      this.pluginManager.registerPlugin(plugin);
      this.sandboxedModules.set(pluginName, sandbox);
      return plugin;
    } catch (err) {
      throw new Error(`Failed to load plugin from code "${pluginName}": ${err.message}`);
    }
  }

  /**
   * Load a plugin from an environment variable
   * Env var can contain either a file path or inline JS code
   */
  loadFromEnv(envVarName) {
    const value = process.env[envVarName];
    if (!value) {
      console.warn(`[PluginLoader] Environment variable "${envVarName}" is not set. Skipping.`);
      return null;
    }

    console.log(`[PluginLoader] Loading plugin from env: ${envVarName}`);

    // Check if it's a file path
    if (value.startsWith('/') || value.startsWith('./') || value.startsWith('../') || value.endsWith('.js')) {
      return this.loadFromFile(value);
    }

    // Treat as inline code
    return this.loadFromCode(value, `env_${envVarName}`);
  }

  /**
   * Load a plugin from a JSON config entry
   */
  loadFromConfig(pluginConfig) {
    if (pluginConfig.file) {
      return this.loadFromFile(pluginConfig.file);
    } else if (pluginConfig.code) {
      return this.loadFromCode(pluginConfig.code, pluginConfig.name || 'config_plugin');
    } else if (pluginConfig.module) {
      // Load from node_modules
      console.log(`[PluginLoader] Loading plugin from module: ${pluginConfig.module}`);
      const plugin = require(pluginConfig.module);
      if (pluginConfig.options && typeof plugin.configure === 'function') {
        plugin.configure(pluginConfig.options);
      }
      this.pluginManager.registerPlugin(plugin);
      return plugin;
    } else if (pluginConfig.env) {
      return this.loadFromEnv(pluginConfig.env);
    }

    throw new Error(`Invalid plugin config: must specify "file", "code", "module", or "env"`);
  }

  /**
   * Load all plugins from the configuration
   */
  loadAll() {
    const plugins = this.config.plugins || [];
    const loaded = [];

    for (const pluginConfig of plugins) {
      try {
        const plugin = this.loadFromConfig(pluginConfig);
        if (plugin) loaded.push(plugin);
      } catch (err) {
        console.error(`[PluginLoader] Failed to load plugin:`, err.message);
        if (this.config.strictPluginLoading) {
          throw err;
        }
      }
    }

    // Load from environment variables
    const envPlugins = this.config.envPlugins || [];
    for (const envVarName of envPlugins) {
      try {
        const plugin = this.loadFromEnv(envVarName);
        if (plugin) loaded.push(plugin);
      } catch (err) {
        console.error(`[PluginLoader] Failed to load env plugin "${envVarName}":`, err.message);
      }
    }

    console.log(`[PluginLoader] Loaded ${loaded.length} plugin(s) total.`);
    return loaded;
  }

  /**
   * Create a sandboxed context for running plugin code
   */
  _createSandbox(pluginName) {
    const allowedModules = this.config.allowedModules || ['url', 'querystring', 'crypto', 'util'];

    const safeRequire = (moduleName) => {
      if (allowedModules.includes(moduleName)) {
        return require(moduleName);
      }
      throw new Error(`Plugin "${pluginName}" attempted to require unauthorized module: "${moduleName}"`);
    };

    return {
      module: { exports: {} },
      exports: {},
      require: safeRequire,
      console: {
        log: (...args) => console.log(`[Plugin:${pluginName}]`, ...args),
        warn: (...args) => console.warn(`[Plugin:${pluginName}]`, ...args),
        error: (...args) => console.error(`[Plugin:${pluginName}]`, ...args),
        info: (...args) => console.info(`[Plugin:${pluginName}]`, ...args),
      },
      setTimeout,
      clearTimeout,
      setInterval,
      clearInterval,
      Buffer,
      URL,
      URLSearchParams,
      Date,
      JSON,
      Math,
      RegExp,
      Array,
      Object,
      String,
      Number,
      Boolean,
      Map,
      Set,
      Promise,
      Error,
      TypeError,
      RangeError,
    };
  }
}

// ============================================
// Request/Response Context
// ============================================
class GatewayContext {
  constructor(req, res) {
    this.req = req;
    this.res = res;
    this.startTime = Date.now();
    this._stopped = false;
    this.state = {}; // Shared state between plugins
    this.parsedUrl = url.parse(req.url, true);

    // Mutable request properties
    this.request = {
      method: req.method,
      url: req.url,
      path: this.parsedUrl.pathname,
      query: this.parsedUrl.query,
      headers: { ...req.headers },
      body: null,
      params: {},
      ip: req.socket.remoteAddress,
    };

    // Mutable response properties
    this.response = {
      statusCode: 200,
      headers: {},
      body: null,
      sent: false,
    };

    // Upstream target
    this.upstream = {
      host: null,
      port: null,
      protocol: 'http',
      path: null,
      timeout: 30000,
    };
  }

  setHeader(name, value) {
    this.response.headers[name.toLowerCase()] = value;
  }

  getHeader(name) {
    return this.request.headers[name.toLowerCase()];
  }

  send(statusCode, body, contentType = 'application/json') {
    if (this.response.sent) return;
    this.response.sent = true;
    this.response.statusCode = statusCode;

    const responseBody = typeof body === 'object' ? JSON.stringify(body) : String(body);

    this.res.writeHead(statusCode, {
      'Content-Type': contentType,
      'Content-Length': Buffer.byteLength(responseBody),
      'X-Response-Time': `${Date.now() - this.startTime}ms`,
      ...this.response.headers,
    });
    this.res.end(responseBody);
  }
}

// ============================================
// API Gateway Server
// ============================================
class APIGateway {
  constructor(config = {}) {
    this.config = {
      port: config.port || 3000,
      host: config.host || '0.0.0.0',
      routes: config.routes || [],
      plugins: config.plugins || [],
      envPlugins: config.envPlugins || [],
      allowedModules: config.allowedModules || ['url', 'querystring', 'crypto', 'util'],
      strictPluginLoading: config.strictPluginLoading || false,
      requestTimeout: config.requestTimeout || 30000,
      maxBodySize: config.maxBodySize || 1024 * 1024, // 1MB
      ...config,
    };

    this.pluginManager = new PluginManager();
    this.pluginLoader = new PluginLoader(this.pluginManager, this.config);
    this.server = null;
    this.routes = new Map();

    this._setupRoutes();
  }

  _setupRoutes() {
    for (const route of this.config.routes) {
      const key = `${route.method || 'ALL'}:${route.path}`;
      this.routes.set(key, route);
    }
  }

  _matchRoute(method, pathname) {
    // Exact match
    let route = this.routes.get(`${method}:${pathname}`) || this.routes.get(`ALL:${pathname}`);
    if (route) return { route, params: {} };

    // Pattern matching with params
    for (const [key, route] of this.routes) {
      const [routeMethod, routePath] = key.split(':');
      if (routeMethod !== 'ALL' && routeMethod !== method) continue;

      const params = this._matchPattern(routePath, pathname);
      if (params) return { route, params };
    }

    return null;
  }

  _matchPattern(pattern, pathname) {
    const patternParts = pattern.split('/');
    const pathParts = pathname.split('/');

    if (patternParts.length !== pathParts.length) {
      // Check for wildcard
      if (!pattern.includes('*')) return null;
    }

    const params = {};
    for (let i = 0; i < patternParts.length; i++) {
      if (patternParts[i] === '*') return params;
      if (patternParts[i].startsWith(':')) {
        params[patternParts[i].slice(1)] = pathParts[i];
      } else if (patternParts[i] !== pathParts[i]) {
        return null;
      }
    }

    return patternParts.length === pathParts.length ? params : null;
  }

  async _readBody(req, maxSize) {
    return new Promise((resolve, reject) => {
      const chunks = [];
      let size = 0;

      req.on('data', (chunk) => {
        size += chunk.length;
        if (size > maxSize) {
          reject(new Error('Request body too large'));
          req.destroy();
          return;
        }
        chunks.push(chunk);
      });

      req.on('end', () => {
        const raw = Buffer.concat(chunks);
        resolve(raw);
      });

      req.on('error', reject);
    });
  }

  async _proxyRequest(ctx) {
    const { upstream } = ctx;

    if (!upstream.host) {
      ctx.send(502, { error: 'No upstream configured for this route' });
      return;
    }

    const protocol = upstream.protocol === 'https' ? https : http;
    const targetPath = upstream.path || ctx.request.path;
    const queryString = url.format({ query: ctx.request.query });
    const fullPath = queryString !== '?' ? `${targetPath}${queryString}` : targetPath;

    const options = {
      hostname: upstream.host,
      port: upstream.port || (upstream.protocol === 'https' ? 443 : 80),
      path: fullPath,
      method: ctx.request.method,
      headers: { ...ctx.request.headers },
      timeout: upstream.timeout || this.config.requestTimeout,
    };

    // Remove hop-by-hop headers
    delete options.headers['connection'];
    delete options.headers['keep-alive'];
    delete options.headers['transfer-encoding'];

    // Set forwarding headers
    options.headers['x-forwarded-for'] = ctx.request.ip;
    options.headers['x-forwarded-host'] = ctx.request.headers.host;
    options.headers['x-forwarded-proto'] = 'http';
    options.headers['host'] = upstream.host;

    return new Promise((resolve) => {
      const proxyReq = protocol.request(options, async (proxyRes) => {
        const chunks = [];
        proxyRes.on('data', (chunk) => chunks.push(chunk));
        proxyRes.on('end', async () => {
          const body = Buffer.concat(chunks);

          ctx.response.statusCode = proxyRes.statusCode;
          ctx.response.headers = { ...proxyRes.headers };
          ctx.response.body = body;

          // Execute onResponse hooks
          await this.pluginManager.executeHook('onResponse', ctx);

          if (!ctx.response.sent) {
            // Remove hop-by-hop headers from response
            const responseHeaders = { ...ctx.response.headers };
            delete responseHeaders['connection'];
            delete responseHeaders['keep-alive'];
            delete responseHeaders['transfer-encoding'];
            responseHeaders['x-response-time'] = `${Date.now() - ctx.startTime}ms`;
            responseHeaders['x-powered-by'] = 'API-Gateway';

            ctx.res.writeHead(ctx.response.statusCode, responseHeaders);
            ctx.res.end(ctx.response.body);
            ctx.response.sent = true;
          }

          resolve();
        });
      });

      proxyReq.on('error', (err) => {
        console.error('[Gateway] Proxy error:', err.message);
        if (!ctx.response.sent) {
          ctx.send(502, { error: 'Bad Gateway', message: err.message });
        }
        resolve();
      });

      proxyReq.on('timeout', () => {
        proxyReq.destroy();
        if (!ctx.response.sent) {
          ctx.send(504, { error: 'Gateway Timeout' });
        }
        resolve();
      });

      // Send body if present
      if (ctx.request.body) {
        proxyReq.write(ctx.request.body);
      }
      proxyReq.end();
    });
  }

  async _handleRequest(req, res) {
    const ctx = new GatewayContext(req, res);

    try {
      // Read body for POST/PUT/PATCH
      if (['POST', 'PUT', 'PATCH'].includes(req.method)) {
        try {
          const rawBody = await this._readBody(req, this.config.maxBodySize);
          ctx.request.body = rawBody;

          // Parse JSON body if applicable
          const contentType = ctx.getHeader('content-type') || '';
          if (contentType.includes('application/json') && rawBody.length > 0) {
            try {
              ctx.request.parsedBody = JSON.parse(rawBody.toString());
            } catch (e) {
              // Keep raw body if JSON parsing fails
            }
          }
        } catch (err) {
          ctx.send(413, { error: 'Payload Too Large' });
          return;
        }
      }

      // Match route
      const match = this._matchRoute(ctx.request.method, ctx.request.path);
      if (match) {
        ctx.request.params = match.params;
        const route = match.route;

        // Set upstream from route config
        if (route.upstream) {
          ctx.upstream = { ...ctx.upstream, ...route.upstream };
        }

        // Route-specific state
        ctx.state.route = route;
      }

      // Execute onRequest hooks
      await this.pluginManager.executeHook('onRequest', ctx);

      // If a plugin already sent a response or stopped the chain, we're done
      if (ctx.response.sent || ctx._stopped) {
        if (!ctx.response.sent) {
          ctx.send(ctx.response.statusCode || 200, ctx.response.body || { ok: true });
        }
        return;
      }

      // Admin endpoints
      if (ctx.request.path === '/_gateway/plugins' && ctx.request.method === 'GET') {
        ctx.send(200, {
          plugins: this.pluginManager.listPlugins(),
        });
        return;
      }

      if (ctx.request.path === '/_gateway/plugins' && ctx.request.method === 'POST') {
        await this._handlePluginInstall(ctx);
        return;
      }

      if (ctx.request.path === '/_gateway/plugins' && ctx.request.method === 'DELETE') {
        await this._handlePluginUninstall(ctx);
        return;
      }

      if (ctx.request.path === '/_gateway/health') {
        ctx.send(200, {
          status: 'healthy',
          uptime: process.uptime(),
          plugins: this.pluginManager.listPlugins().length,
          routes: this.routes.size,
        });
        return;
      }

      if (ctx.request.path === '/_gateway/routes') {
        ctx.send(200, {
          routes: Array.from(this.routes.entries()).map(([key, route]) => ({
            key,
            upstream: route.upstream,
          })),
        });
        return;
      }

      // If no route matched and no upstream is configured
      if (!match && !ctx.upstream.host) {
        ctx.send(404, { error: 'Not Found', path: ctx.request.path });
        return;
      }

      // Proxy the request to upstream
      await this._proxyRequest(ctx);
    } catch (err) {
      console.error('[Gateway] Unhandled error:', err);
      await this.pluginManager.executeHook('onError', { ...ctx, error: err });
      if (!ctx.response.sent) {
        ctx.send(500, { error: 'Internal Server Error' });
      }
    }
  }

  async _handlePluginInstall(ctx) {
    try {
      if (!ctx.request.parsedBody) {
        ctx.send(400, { error: 'Request body must be JSON with plugin configuration' });
        return;
      }

      const pluginConfig = ctx.request.parsedBody;

      if (pluginConfig.code) {
        this.pluginLoader.loadFromCode(pluginConfig.code, pluginConfig.name || 'dynamic');
      } else if (pluginConfig.file) {
        this.pluginLoader.loadFromFile(pluginConfig.file);
      } else {
        ctx.send(400, { error: 'Plugin config must include "code" or "file"' });
        return;
      }

      ctx.send(201, {
        message: 'Plugin installed successfully',
        plugins: this.pluginManager.listPlugins(),
      });
    } catch (err) {
      ctx.send(400, { error: `Plugin installation failed: ${err.message}` });
    }
  }

  async _handlePluginUninstall(ctx) {
    const pluginName = ctx.request.parsedBody?.name || ctx.request.query.name;
    if (!pluginName) {
      ctx.send(400, { error: 'Plugin "name" is required' });
      return;
    }

    this.pluginManager.unregisterPlugin(pluginName);
    ctx.send(200, {
      message: `Plugin "${pluginName}" uninstalled`,
      plugins: this.pluginManager.listPlugins(),
    });
  }

  async start() {
    // Load plugins from configuration
    this.pluginLoader.loadAll();

    // Execute startup hooks
    await this.pluginManager.executeHook('onStartup', { gateway: this });

    // Create and start server
    this.server = http.createServer((req, res) => this._handleRequest(req, res));

    return new Promise((resolve) => {
      this.server.listen(this.config.port, this.config.host, () => {
        console.log(`[Gateway] API Gateway running on http://${this.config.host}:${this.config.port}`);
        console.log(`[Gateway] Loaded ${this.pluginManager.listPlugins().length} plugin(s)`);
        console.log(`[Gateway] Configured ${this.routes.size} route(s)`);
        console.log(`[Gateway] Admin endpoints available at /_gateway/*`);
        resolve(this);
      });
    });
  }

  async stop() {
    await this.pluginManager.executeHook('onShutdown', { gateway: this });
    if (this.server) {
      return new Promise((resolve) => {
        this.server.close(() => {
          console.log('[Gateway] Server stopped');
          resolve();
        });
      });
    }
  }
}

// ============================================
// Load configuration
// ============================================
function loadConfig() {
  // Try loading from config file
  const configPath = process.env.GATEWAY_CONFIG || path.join(__dirname, 'gateway.config.json');

  let config = {
    port: parseInt(process.env.GATEWAY_PORT || '3000', 10),
    host: process.env.GATEWAY_HOST || '0.0.0.0',
    routes: [],
    plugins: [],
    envPlugins: [],
    allowedModules: ['url', 'querystring', 'crypto', 'util'],
    strictPluginLoading: false,
    requestTimeout: 30000,
    maxBodySize: 1024 * 1024,
  };

  if (fs.existsSync(configPath)) {
    try {
      const fileConfig = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
      config = { ...config, ...fileConfig };
      console.log(`[Config] Loaded configuration from ${configPath}`);
    } catch (err) {
      console.error(`[Config] Failed to load config from ${configPath}:`, err.message);
    }
  } else {
    console.log('[Config] No config file found. Using defaults and environment variables.');
  }

  // Override with env vars
  if (process.env.GATEWAY_ROUTES) {
    try {
      config.routes = JSON.parse(process.env.GATEWAY_ROUTES);
    } catch (e) {
      console.error('[Config] Failed to parse GATEWAY_ROUTES env var');
    }
  }

  if (process.env.GATEWAY_PLUGINS) {
    try {
      const envPluginsConfig = JSON.parse(process.env.GATEWAY_PLUGINS);
      config.plugins = [...config.plugins, ...envPluginsConfig];
    } catch (e) {
      console.error('[Config] Failed to parse GATEWAY_PLUGINS env var');
    }
  }

  if (process.env.GATEWAY_ENV_PLUGINS) {
    config.envPlugins = process.env.GATEWAY_ENV_PLUGINS.split(',').map(s => s.trim());
  }

  return config;
}

