// ============================================
// Create sample plugins
// ============================================
function createSamplePlugins() {
  const pluginsDir = path.join(__dirname, 'plugins');

  if (!fs.existsSync(pluginsDir)) {
    fs.mkdirSync(pluginsDir, { recursive: true });
  }

  // Request Logger Plugin
  const loggerPlugin = `
module.exports = {
  name: 'request-logger',
  version: '1.0.0',
  description: 'Logs all incoming requests and response times',
  priority: 100,
  hooks: {
    onRequest: async (ctx) => {
      const timestamp = new Date().toISOString();
      console.log(\`[RequestLogger] [\${timestamp}] \${ctx.request.method} \${ctx.request.url} from \${ctx.request.ip}\`);
      ctx.state.requestStartTime = Date.now();
    },
    onResponse: async (ctx) => {
      const duration = Date.now() - (ctx.state.requestStartTime || ctx.startTime);
      console.log(\`[RequestLogger] \${ctx.request.method} \${ctx.request.url} -> \${ctx.response.statusCode} (\${duration}ms)\`);
    },
    onError: async (ctx) => {
      console.error(\`[RequestLogger] ERROR: \${ctx.error?.message} in \${ctx.request?.method} \${ctx.request?.url}\`);
    },
    onStartup: async (ctx) => {
      console.log('[RequestLogger] Plugin started');
    },
    onShutdown: async (ctx) => {
      console.log('[RequestLogger] Plugin shutting down');
    }
  }
};
`;

  // CORS Plugin
  const corsPlugin = `
module.exports = {
  name: 'cors',
  version: '1.0.0',
  description: 'Adds CORS headers to responses',
  priority: 90,
  _config: {
    allowOrigin: '*',
    allowMethods: 'GET, POST, PUT, DELETE, PATCH, OPTIONS',
    allowHeaders: 'Content-Type, Authorization, X-Requested-With',
    maxAge: '86400',
    allowCredentials: 'true',
  },
  configure(options) {
    Object.assign(this._config, options);
  },
  hooks: {
    onRequest: async (ctx) => {
      const config = module.exports._config;

      // Handle preflight
      if (ctx.request.method === 'OPTIONS') {
        ctx.send(204, '', 'text/plain');
        ctx.setHeader('access-control-allow-origin', config.allowOrigin);
        ctx.setHeader('access-control-allow-methods', config.allowMethods);
        ctx.setHeader('access-control-allow-headers', config.allowHeaders);
        ctx.setHeader('access-control-max-age', config.maxAge);
        if (config.allowCredentials === 'true') {
          ctx.setHeader('access-control-allow-credentials', 'true');
        }
        return { stop: true };
      }
    },
    onResponse: async (ctx) => {
      const config = module.exports._config;
      ctx.response.headers['access-control-allow-origin'] = config.allowOrigin;
      ctx.response.headers['access-control-allow-methods'] = config.allowMethods;
      ctx.response.headers['access-control-allow-headers'] = config.allowHeaders;
      if (config.allowCredentials === 'true') {
        ctx.response.headers['access-control-allow-credentials'] = 'true';
      }
    }
  }
};
`;

  // Rate Limiter Plugin
  const rateLimiterPlugin = `
const rateLimitStore = new Map();

function cleanupStore() {
  const now = Date.now();
  for (const [key, data] of rateLimitStore) {
    if (now - data.windowStart > 60000) {
      rateLimitStore.delete(key);
    }
  }
}

// Cleanup every minute
setInterval(cleanupStore, 60000);

module.exports = {
  name: 'rate-limiter',
  version: '1.0.0',
  description: 'Simple in-memory rate limiter',
  priority: 95,
  _config: {
    windowMs: 60000,   // 1 minute
    maxRequests: 100,   // Max requests per window
    keyGenerator: (ctx) => ctx.request.ip,
  },
  configure(options) {
    Object.assign(this._config, options);
  },
  hooks: {
    onRequest: async (ctx) => {
      const config = module.exports._config;
      const key = config.keyGenerator(ctx);
      const now = Date.now();

      let record = rateLimitStore.get(key);
      if (!record || now - record.windowStart > config.windowMs) {
        record = { count: 0, windowStart: now };
        rateLimitStore.set(key, record);
      }

      record.count++;

      // Set rate limit headers
      ctx.setHeader('x-ratelimit-limit', String(config.maxRequests));
      ctx.setHeader('x-ratelimit-remaining', String(Math.max(0, config.maxRequests - record.count)));
      ctx.setHeader('x-ratelimit-reset', String(Math.ceil((record.windowStart + config.windowMs) / 1000)));

      if (record.count > config.maxRequests) {
        ctx.send(429, {
          error: 'Too Many Requests',
          retryAfter: Math.ceil((record.windowStart + config.windowMs - now) / 1000),
        });
        return { stop: true };
      }
    }
  }
};
`;

  // Auth Plugin
  const authPlugin = `
module.exports = {
  name: 'auth',
  version: '1.0.0',
  description: 'Simple API key authentication',
  priority: 85,
  _config: {
    apiKeys: {
      'test-key-123': { name: 'Test User', roles: ['read'] },
      'admin-key-456': { name: 'Admin User', roles: ['read', 'write', 'admin'] },
    },
    headerName: 'x-api-key',
    excludePaths: ['/_gateway/', '/health'],
  },
  configure(options) {
    Object.assign(this._config, options);
  },
  hooks: {
    onRequest: async (ctx) => {
      const config = module.exports._config;

      // Check if path is excluded
      const isExcluded = config.excludePaths.some(p => ctx.request.path.startsWith(p));
      if (isExcluded) return;

      const apiKey = ctx.getHeader(config.headerName);

      if (!apiKey) {
        ctx.send(401, {
          error: 'Unauthorized',
          message: 'Missing API key. Include it in the "' + config.headerName + '" header.',
        });
        return { stop: true };
      }

      const keyData = config.apiKeys[apiKey];
      if (!keyData) {
        ctx.send(403, {
          error: 'Forbidden',
          message: 'Invalid API key.',
        });
        return { stop: true };
      }

      // Attach user info to context
      ctx.state.user = keyData;
      ctx.request.headers['x-authenticated-user'] = keyData.name;
      ctx.request.headers['x-user-roles'] = keyData.roles.join(',');
    }
  }
};
`;

  const files = {
    'request-logger.js': loggerPlugin,
    'cors.js': corsPlugin,
    'rate-limiter.js': rateLimiterPlugin,
    'auth.js': authPlugin,
  };

  for (const [filename, content] of Object.entries(files)) {
    const filePath = path.join(pluginsDir, filename);
    if (!fs.existsSync(filePath)) {
      fs.writeFileSync(filePath, content.trim());
      console.log(`[Setup] Created sample plugin: ${filePath}`);
    }
  }
}

// ============================================
// Main Entry Point
// ============================================
async function main() {
  console.log('===========================================');
  console.log('  Extensible API Gateway Platform');
  console.log('===========================================\n');

  // Create sample files if they don't exist
  createSamplePlugins();
  createSampleConfig();

  // Load configuration
  const config = loadConfig();

  // Create and start gateway
  const gateway = new APIGateway(config);

  // Handle graceful shutdown
  const shutdown = async (signal) => {
    console.log(`\n[Gateway] Received ${signal}. Shutting down gracefully...`);
    await gateway.stop();
    process.exit(0);
  };

  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGTERM', () => shutdown('SIGTERM'));

  process.on('uncaughtException', (err) => {
    console.error('[Gateway] Uncaught exception:', err);
  });

  process.on('unhandledRejection', (reason) => {
    console.error('[Gateway] Unhandled rejection:', reason);
  });

  await gateway.start();

  console.log('\n[Gateway] Example usage:');
  console.log(`  curl http://localhost:${config.port}/_gateway/health`);
  console.log(`  curl http://localhost:${config.port}/_gateway/plugins`);
  console.log(`  curl http://localhost:${config.port}/_gateway/routes`);
  console.log(`\n[Gateway] Install a plugin dynamically:`);
  console.log(`  curl -X POST http://localhost:${config.port}/_gateway/plugins \\`);
  console.log(`    -H "Content-Type: application/json" \\`);
  console.log(`    -d '{"name":"my-plugin","code":"module.exports={name:\\"my-plugin\\",version:\\"1.0.0\\",hooks:{onRequest:async(ctx)=>{ctx.setHeader(\\"x-custom\\",\\"hello\\");}}}"}'`);
}

main().catch((err) => {
  console.error('[Fatal]', err);
  process.exit(1);
});

module.exports = { APIGateway, PluginManager, PluginLoader, GatewayContext };